// ---------------------------------------------------------------------------
// Lasso
// ---------------------------------------------------------------------------

#[test]
fn sklearn_equiv_lasso() {
    let fixture: serde_json::Value = serde_json::from_str(include_str!(
        "../../tests/fixtures/sklearn_reference/lasso.json"
    ))
    .unwrap();

    let x = json_to_array2(&fixture["X_train"]);
    let y = json_to_array1(&fixture["y_train"]);
    let expected_coef = json_to_array1(&fixture["coef"]);
    let expected_intercept = fixture["intercept"].as_f64().unwrap();
    let expected_preds = json_to_array1(&fixture["predictions_train"]);
    let alpha = fixture["params"]["alpha"].as_f64().unwrap();

    let model = ferrolearn_linear::Lasso::<f64>::new()
        .with_alpha(alpha)
        .with_fit_intercept(true)
        .with_max_iter(10_000)
        .with_tol(1e-8);
    let fitted = model.fit(&x, &y).unwrap();

    // Coordinate descent: looser tolerance (1e-3 for coefficients).
    assert_array_close(
        fitted.coefficients().as_slice().unwrap(),
        expected_coef.as_slice().unwrap(),
        1e-3,
        "Lasso coef",
    );

    let diff = (fitted.intercept() - expected_intercept).abs();
    let denom = expected_intercept.abs().max(1.0);
    assert!(
        diff / denom < 1e-3,
        "Lasso intercept: actual={}, expected={expected_intercept}",
        fitted.intercept()
    );

    let preds = fitted.predict(&x).unwrap();
    assert_array_close(
        preds.as_slice().unwrap(),
        expected_preds.as_slice().unwrap(),
        1e-2,
        "Lasso predictions",
    );
}

